@import (reference) "../style/themes/default.less";

.am-guide .am-button-ghost {
  --am-button-ghost-border-color: @color-text-base;
  --am-button-ghost-color: @color-text-base;
}
.am-guide {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  &-content {
    position: relative;
    z-index: 2;
    width: 100vw;
    height: 100vh;
    overflow: hidden;
    padding-bottom: 208 * @pixelSize;
    box-sizing: border-box;
    &-pager {
      padding-bottom: 260 * @pixelSize;
    }
  }
  &-img {
    position: absolute;
    z-index: 2;
  }
  &-btn {
    position: absolute;
    bottom: 120 * @pixelSize;
    left: 0;
    right: 0;
    display: flex;
    justify-content: center;
    z-index: 5;
    &-item {
      margin-right: @h-spacing-large;
      &:last-child {
        margin-right: 0;
      }
    }
  }
  &-pager {
    position: absolute;
    bottom: 196 * @pixelSize;
    left: 0;
    right: 0;
    z-index: 5;
  }
}

// Close icons
// --------------------------------------------------
@prefix-cls-close: e("@{prefix-cls}-close");

@close-font-weight:           bold;
@close-color:                 #000;
@close-text-shadow:           0 1px 0 #fff;

.@{prefix-cls-close} {
  float: right;
  font-size: (@font-size-base * 1.5);
  font-weight: @close-font-weight;
  line-height: 1;
  color: @close-color;
  text-shadow: @close-text-shadow;
  opacity: .2;

  &:hover,
  &:focus {
    color: @close-color;
    text-decoration: none;
    cursor: pointer;
    opacity: .5;
  }

  // Additional properties for button version
  // iOS requires the button element instead of an anchor tag.
  // If you want the anchor version, it requires `href="#"`.
  // See https://developer.mozilla.org/en-US/docs/Web/Events/click#Safari_Mobile
  button& {
    padding: 0;
    cursor: pointer;
    background: transparent;
    border: 0;
    appearance: none;
  }
}

// Image Mixins
// - Responsive image
// - Retina image


// Responsive image
//
// Keep images from scaling beyond the width of their parents.
.img-responsive(@display: block) {
  display: @display;
  max-width: 100%; // Part 1: Set a maximum relative to the parent
  height: auto; // Part 2: Scale the height according to the width, otherwise you get stretching
}


// Retina image
//
// Short retina mixin for setting background-image and -size. Note that the
// spelling of `min--moz-device-pixel-ratio` is intentional.
.img-retina(@file-1x; @file-2x; @width-1x; @height-1x) {
  background-image: url("@{file-1x}");

  @media
  only screen and (-webkit-min-device-pixel-ratio: 2),
  only screen and (min--moz-device-pixel-ratio: 2),
  only screen and (-o-min-device-pixel-ratio: 2 / 1),
  only screen and (min-device-pixel-ratio: 2),
  only screen and (min-resolution: 192dpi),
  only screen and (min-resolution: 2dppx) {
    background-image: url("@{file-2x}");
    background-size: @width-1x @height-1x;
  }
}

// Breadcrumbs
// --------------------------------------------------
@prefix-cls-breadcrumb: e("@{prefix-cls}-breadcrumb");
@prefix-cls-breadcrumbs: e("@{prefix-cls}-breadcrumbs");

@breadcrumb-link-color: #999999;
@breadcrumb-last-link-color: #666;
@breadcrumb-slash-color: #ccc;

.@{prefix-cls-breadcrumbs} {
  .@{prefix-cls-breadcrumb} {
    padding: 0;
    background-color: #fff;
    .@{prefix-cls-breadcrumb}-link {
      padding: 0 16px;
      color: @breadcrumb-link-color;
      font-size: 12px;
    }
  }

  .@{prefix-cls-breadcrumb}:last-child .@{prefix-cls-breadcrumb}-link {
    color: @breadcrumb-last-link-color;
  }

  .@{prefix-cls-breadcrumb}-symbol {
    color: @breadcrumb-slash-color;
    font-size: 12px;
  }

  span:last-child .@{prefix-cls-breadcrumb}-symbol {
    display: none;
  }
}

@class-prefix-rate: ~'adm-rate';

.@{class-prefix-rate} {
  --star-size: 24px;
  --active-color: var(--adm-color-yellow);
  --inactive-color: var(--adm-color-border);
  --inactive-color-half: var(--adm-color-border);

  display: inline-flex;
  touch-action: pan-y;
  user-select: none;
  &-box {
    position: relative;
  }

  &-star {
    padding: 0.125em;
    line-height: var(--star-size);
    font-size: var(--star-size);
    color: var(--inactive-color);
    text-align: center;
    overflow: hidden;
    cursor: pointer;
    box-sizing: border-box;
    transition: all 0.3s;
    &-half {
      padding-right: 0;
      width: 50%;
      position: absolute;
      left: 0;
      top: 0;
    }
    &-active {
      color: var(--active-color);
    }
    &-readonly {
      cursor: unset;
    }
  }

  &&-half {
    .@{class-prefix-rate}-star-half:not(.@{class-prefix-rate}-star-active) {
      color: var(--inactive-color-half);
    }
  }
}

@class-prefix-progress-bar: ~'adm-progress-bar';

.@{class-prefix-progress-bar} {
  --track-width: var(--adm-progress-bar-track-width, 8px);
  --track-color: var(--adm-progress-bar-track-color, var(--adm-color-border));
  --fill-color: var(--adm-progress-bar-fill-color, var(--adm-color-primary));
  --text-width: var(--adm-progress-bar-text-width, 40px);

  display: flex;
  align-items: center;
  &-trail {
    flex: auto;
    background: var(--track-color);
    overflow: hidden;
    height: var(--track-width);
  }
  &-fill {
    transition: width 0.3s;
    background: var(--fill-color);
    height: var(--track-width);
  }
  &-text {
    flex: none;
    width: calc(var(--text-width) + 8px);
    padding-left: 8px;
    color: var(--adm-color-weak);
  }
}

.@{class-prefix-progress-bar}-rounded {
  .@{class-prefix-progress-bar}-trail,
  .@{class-prefix-progress-bar}-fill {
    border-radius: var(--track-width);
  }
}

@class-prefix-tab-bar: ~'adm-tab-bar';

.@{class-prefix-tab-bar} {
  &-wrap {
    display: flex;
    flex-wrap: nowrap;
    justify-content: flex-start;
    align-items: stretch;
    overflow: hidden;
    min-height: 48px;
  }

  &-item {
    flex: 1;
    color: var(--adm-color-text-secondary);
    white-space: nowrap;
    padding: 4px 8px;
    width: min-content;
    position: relative;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
  }

  &-item-icon {
    font-size: 24px;
    height: 24px;
    line-height: 1;
  }

  &-item-title {
    font-size: var(--adm-font-size-2);
    line-height: 15px;
    &-with-icon {
      margin-top: 2px;
    }
  }

  &-item-active {
    color: var(--adm-color-primary);
  }

  &-icon-badge {
    --top: 6px;
  }
  &-title-badge {
    --right: -2px;
    --top: -2px;
  }
}

@class-prefix-toast: ~'adm-toast';

.@{class-prefix-toast}-mask {
  .@{class-prefix-toast}-wrap {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    text-align: center;
  }
  .@{class-prefix-toast}-main {
    display: inline-block;
    position: relative;
    top: 50%;
    transform: translateY(-50%);
    width: auto;
    max-width: 204px;
    max-height: 70%;
    overflow: auto;
    color: white;
    word-break: break-all;
    background-color: rgba(0, 0, 0, 0.7);
    border-radius: 8px;
    pointer-events: all;
    font-size: var(--adm-font-size-7);
    line-height: 1.5;
    box-sizing: border-box;
    text-align: initial;
  }
  .@{class-prefix-toast}-main-text {
    padding: 12px;
    min-width: 0;
  }
  .@{class-prefix-toast}-main-icon {
    padding: 35px 12px;
    min-width: 150px;
    .@{class-prefix-toast}-icon {
      text-align: center;
      margin-bottom: 8px;
      font-size: 36px;
      line-height: 1;
    }
  }
}

.@{class-prefix-toast}-loading {
  --size: 48px;
  margin: 0 auto 8px;
}

@class-prefix-form: ~'adm-form';

.@{class-prefix-form} {
  --border-inner: solid 1px var(--adm-border-color);
  --border-top: solid 1px var(--adm-border-color);
  --border-bottom: solid 1px var(--adm-border-color);
  --prefix-width: 6.8em;

  ---border-inner: var(--border-inner);
  ---border-top: var(--border-top);
  ---border-bottom: var(--border-bottom);
  ---prefix-width: var(--prefix-width);
  .adm-list.adm-list {
    --padding-left: 16px;
    --padding-right: 12px;
    --border-inner: var(---border-inner);
    --border-top: var(---border-top);
    --border-bottom: var(---border-bottom);
  }
  .@{class-prefix-form}-footer {
    padding: 20px 12px;
  }
  .@{class-prefix-form}-item-horizontal {
    &.adm-list-item {
      --prefix-width: var(---prefix-width);
    }
  }
}

.adm-form-list-operation {
  text-align: center;
  color: var(--adm-color-primary);
}

@class-prefix-picker: ~'adm-cascader';

.@{class-prefix-picker} {
  width: 100%;
  overflow: hidden;
  position: relative;
  display: flex;
  flex-direction: column;
}

.@{class-prefix-picker}-header {
  flex: none;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6px 8px;
  &-button {
    font-size: var(--adm-font-size-7);
    display: inline-block;
    padding: 4px 4px;
  }
  &-title {
    padding: 4px 4px;
    font-size: var(--adm-font-size-7);
    color: var(--adm-color-text);
    text-align: center;
    flex: 1;
  }
}

.@{class-prefix-picker}-body {
  flex: auto;
  height: 100%;
  width: 100%;
  > .adm-cascader-view {
    --height: 310px;
  }
}

.@{class-prefix-picker}-popup {
  & .adm-popup-body {
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
  }
}

// 文字色
@color-text-base: #000;  // 基本文字
@color-link: @brand-primary; // 链接
@color-text-title: #333; // 标题
@color-text-caption: #999; // 副文本
@color-text-dark: #ccc; // 暗文字

// 全局/品牌色
@brand-primary: #108ee9;
@brand-error: #ff3b30; // 错误提示
@brand-emphasis: #f24724; // 强调色
@brand-gradient: #0a73cf; // 渐变品牌色

// 背景色
@fill-base: #fff;
@fill-body: #f5f5f5; // 页面背景
@fill-mask: rgba(0, 0, 0, 0.65); // 蒙层背景

// 边框色
@border-color-base: #eee;

// 按钮
@btn-primary: @brand-primary; // 主按钮色
@btn-disabled: rgba(16, 142, 232, 0.6); // 按钮不可点击
@btn-tap: #0b71ba; // 按钮按下

// 字体大小
@font-size-base: 12px; // 常规文本
@font-size-caption: 14px; // 副文本
@font-size-title-sm: 17px; // 控件中主操作标题
@font-size-title-lg: 18px; // 需要强调标题
@font-size-page-result: 20px; // 结果页标题、异常页面标题
@font-size-amount: 48px; // 输入金额

// 投影色
@box-shadow-primary: #999; // 白色卡片投影

// 圆角
@radius-xs: 2px;
@radius-sm: 3px;
@radius-md: 4px;
@radius-circle: 50%;

// z-index
@popover-zindex: 1999;
@picker-zindex: 1000;
@popup-zindex: 999;
@modal-zindex: 999;

// Text
// -------------------

.text-smaller {
  font-size: smaller;
}

.text-subtle    { color: @text-color-subtle; }
.text-highlight { color: @text-color-highlight; }

.text-info    { color: @text-color-info; }
.text-success { color: @text-color-success; }
.text-warning { color: @text-color-warning; }
.text-error   { color: @text-color-error; }


// Highlights ---------------

.highlight         { .highlight-mixin(@background-color-highlight); }
.highlight-info    { .highlight-mixin(@background-color-info); }
.highlight-warning { .highlight-mixin(@background-color-warning); }
.highlight-error   { .highlight-mixin(@background-color-error); }
.highlight-success { .highlight-mixin(@background-color-success); }

.highlight-mixin(@color) {
  padding: 1px 4px;
  color: @text-color-highlight;
  border-radius: @component-border-radius;
  background-color: @color;
}


// Background Message ---------------
// Shown when no tabs are open.

.background-message {
  font-weight: bold;
  color: @text-color-subtle;
}

@rating-icon: @icon-s-star;
@rating-icon__width: @5;
@rating-icon__height: @6;
@rating-icon__color: false;

@review-action__font-size: @font-size__sm;
@review-action__line-height: @line-height__sm;
@review-action__text-decoration: false;
@review-action__color: false;

@review-list__gap: @8;
@review-list__md__gap: false;

@review-item__gap: @2;
@review-item__padding: false;
@review-item__background: false;
@review-item__border: false;
@review-item__border-radius: false;
@review-item__md__padding: false;

@review-title__font-weight: 500;
@review-title__font-size: false;

@review-content__margin: 0 0 @1;
@review-content__font-family: false;
@review-content__font-weight: false;
@review-content__font-size: false;
@review-content__line-height: false;

.breeze-tokens() {
    .lib-css(--rating-icon-color, @rating-icon__color);
}

& when (@critical) {
    .spinner {
        .spinner();
    }
    .loading-mask,
    .load.indicator {
        inset: 0;
        margin: auto;
        position: fixed;
        z-index: 800;
        background: color-mix(in oklch, var(--base-bg) 40%, transparent);
        display: flex;
        align-items: center;
        justify-content: center;
        body > & {
            z-index: 990;
        }
    }
    .loading-mask {
        body > & {
            position: fixed !important;
        }
        .loader {
            &:extend(.spinner);
            flex-shrink: 0;
            flex-grow: 0;
            p,
            img {
                display: none;
            }
        }
    }
    ._block-content-loading {
        position: relative;
    }
}

& when not (@critical) {
    .loading-mask {
        + .loading-mask {
            opacity: 0;
        }
    }

    .load.indicator {
        &[style*="display: inline"] {
            display: flex !important;
        }
        &::before {
            content: '';
            display: block;
            &:extend(.spinner);
        }
        span {
            display: none;
        }
    }
}

@page__max-width: false;
@page__background: false;

@page-main__padding-top: false;
@page-main__padding-bottom: false;

@page-title-wrapper-without-breadcrumbs__margin-top: false;

@narrow-page__padding-bottom: @12;
@narrow-page-title__margin: @16 0;
@narrow-page-title__text-align: center;

@boxed-page: true;
@boxed-page-contact: true;
@boxed-page-login: true;
@boxed-page-404: true; // enabled for 1column layout only

@sidebar__width: 180px;
@sidebar__gap: @4;
@sidebar__media-lg__width: 220px;
@sidebar__media-lg__gap: @8;

@before-footer__padding-top: false;
@before-footer__padding-bottom: @before-footer__padding-top;

.breeze-tokens() {
    .lib-css(--page-max-width, @page__max-width);
    .lib-css(--page-bg, @page__background);

    --sidebar-width: @sidebar__width;
    --sidebar-gap: @sidebar__gap;
    @media @media-lg {
        --sidebar-width: @sidebar__media-lg__width;
        --sidebar-gap: @sidebar__media-lg__gap;
    }
}

& when (@critical) {
    #store-pickup {
        padding-bottom: 0;
        .form-login {
            margin: @4 0;
        }
    }
    #opc-store-selector-popup {
        display: none;
    }
    #delivery-method-selector ~ div {
        margin-top: @4;
    }
    #store-pickup.selected-store-pickup ~ #shipping,
    #store-pickup.selected-store-pickup ~ #opc-shipping_method {
        padding: 0;
        height: 0;
        visibility: hidden;
        overflow: hidden;
    }
}

& when not (@critical) {
    .store-selector-popup {
        .modal-content {
            padding-top: @1;
        }
    }
    .store-selector-search {
        display: flex;
        gap: @2;
        .label {
            display: none;
            + .control {
                margin-top: 0;
            }
        }
        .field {
            flex-grow: 1;
        }
        .actions .search {
            height: 100%;
        }
    }
    .store-selector-popup-empty-query,
    .store-selector-popup-no-locations {
        margin-top: @2;
        color: var(--muted-color);
    }
}

@price__color: false;
@price__font-family: false;
@price__font-weight: false;
@price__font-size: false;
@price__line-height: false;

@price-label__color: ~"var(--muted-color)";
@price-label__font-size: @font-size__base;
@price-label__line-height: @line-height__base;
@price-label__font-weight: false;

@price-link__color: false;

@price-normal-label__display: false;
@price-minimal__display: false;
@price-special__color: false;

@price-old__color: ~"var(--muted-color)";
@price-old__text-decoration: false;
@price-old__text-decoration-color: false;
@price-old-label__display: false;

@price-tax__font-size: @font-size__sm;
@price-tax__line-height: @line-height__base;

// Listing-specific styles
@listing-price__color: false;
@listing-price__font-size: false;

.breeze-tokens() {
    .lib-css(--price-color, @price__color);
    .lib-css(--price-label-color, @price-label__color);
}

